def is_anagram(s1, s2):
    # 两个字符串的长度必须相等
    if len(s1) != len(s2):
        return False

    # 创建一个计数器来存储每个字母出现的次数
    counter = {}

    # 遍历第一个字符串，增加计数器中字母的计数
    for char in s1:
        if char in counter:
            counter[char] += 1
        else:
            counter[char] = 1

    # 遍历第二个字符串，减少计数器中字母的计数
    for char in s2:
        if char in counter:
            counter[char] -= 1
        else:
            # 如果字母不在计数器中，则两个字符串不是彼此的字谜
            return False

    # 检查计数器中每个字母的计数是否为零
    for count in counter.values():
        if count != 0:
            return False

    return True
```

